        Loại_khách_hàng: typeKey,
        Thân_phận_khách_hàng: identity,
        Tuổi_khách_hàng: age,
        Giới_thiệu_khách_hàng: `${age} tuổi, ${identity}`,
        Báo_giá: price,
        Yêu_cầu_đặc_biệt: request,
        Thời_gian_hẹn: isUrgent ? 'Ngay lập tức' : 'Tối nay',
        Địa_điểm_hẹn: location,
        Trạng_thái_đơn_hàng: 'Chờ xác nhận',
        Loại_đơn_hàng: isUrgent ? 'Đơn gấp' : 'Đơn thường',
        Ghi_chú: isUrgent ? 'Đơn gấp tăng 50%' : 'Không có'
      };
    }

    async function refreshOrders() {
      const data = Mvu.getMvuData({ type: 'message', message_id: getCurrentMessageId() });
      const current = _.get(data, 'stat_data.Đơn_hàng_chờ_nhận', {});

      const cleaned = {};
      Object.keys(current).forEach(k => {
        const o = current[k];
        if (o.Trạng_thái_đơn_hàng && !['Đã hoàn thành', 'Đã từ chối', 'Đã hủy'].includes(o.Trạng_thái_đơn_hàng)) {
          cleaned[k] = o;
        }
      });

      const normalCount = randRange(1, 2);
      const urgentCount = Math.random() > 0.6 ? 1 : 0;
      const totalCount = normalCount + urgentCount;
      const existing = Object.keys(cleaned).length;

      let addedCount = 0;

      for (let i = 0; i < normalCount; i++) {
        const num = existing + addedCount + 1;
        const id = `Đơn hàng ${String(num).padStart(3, '0')}`;
        const order = generateOrder(false);
        cleaned[id] = order;
        addedCount++;
      }

      for (let i = 0; i < urgentCount; i++) {
        const num = existing + addedCount + 1;
        const id = `Đơn gấp${String(num).padStart(3, '0')}`;
        const order = generateOrder(true);
        cleaned[id] = order;
        addedCount++;
      }

      _.set(data, 'stat_data.Đơn_hàng_chờ_nhận', cleaned);
      await Mvu.replaceMvuData(data, { type: 'message', message_id: getCurrentMessageId() });

      return { total: totalCount, urgent: urgentCount };
    }

    function genMessage(id, o) {
      const isUrgent = o.Loại_đơn_hàng === 'Đơn gấp';
      let msg = `[Chi tiết đơn hàng: ${id}]${isUrgent ? ' ⚡Đơn gấp⚡' : ''}\n\n`;
      msg += `Tên khách hàng: ${o.Tên_khách_hàng}\n`;
      msg += `Loại khách hàng: ${o.Loại_khách_hàng}\n`;
      msg += `Thân phận: ${o.Thân_phận_khách_hàng}\n`;
      msg += `Tuổi: ${o.Tuổi_khách_hàng} tuổi\n`;
      msg += `Giới thiệu khách hàng: ${o.Giới_thiệu_khách_hàng}\n`;
      msg += `Địa điểm: ${o.Địa_điểm_hẹn}\n`;
      msg += `Báo giá: ¥${o.Báo_giá.toLocaleString()}${isUrgent ? ' (Đơn gấp+50%)' : ''}\n`;
      if (o.Yêu_cầu_đặc_biệt !== 'Không') msg += `Yêu cầu: ${o.Yêu_cầu_đặc_biệt}\n`;
      if (isUrgent) msg += `\n⚠️ Đơn gấp xử lý nhanh!\n`;
      msg += `\n---\n`;
      msg += `Hành động: nhận đơn`;
      return msg;
    }

    async function init() {
      await waitGlobalInitialized('Mvu');

      function render() {
        const vars = getAllVariables();
        const w = _.get(vars, 'stat_data.Thế_giới', {});
        $('#world-date').text(w.Ngày_tháng || 'Chưa rõ');
        $('#world-time').text(w.Thời_gian || 'Chưa rõ');
        $('#world-location').text(w.Địa_điểm || 'Chưa rõ');
        $('#world-weather').text(w.Thời_tiết || 'Nắng');

        const u = _.get(vars, 'stat_data.user', {});
        $('#user-status').text(u.Trạng_thái_hiện_tại || 'Bình thường');

        const debt = u.Tiền_nợ_bệnh_viện || 0;
        const paid = u.Tiền_đã_trả_bệnh_viện || 0;
        const save = u.Tiền_tiết_kiệm_hiện_tại || 0;

        $('#debt-value').text(`¥${(debt/10000).toFixed(1)}w`);
        $('#user-savings').text(`¥${save.toLocaleString()}`);

        if (debt + paid > 0) {
          const pct = (paid / (debt + paid)) * 100;
          $('#debt-paid-fill').css('width', pct + '%');
          $('#debt-paid-value').text(pct.toFixed(1) + '%');
        }

        const s = _.get(vars, 'stat_data.Em_gái', {});
        $('#sister-age').text(s.Tuổi || 'Chưa rõ');
        $('#sister-outfit').text(s.Trang_phục || 'Chưa rõ');
        $('#sister-health').text(s.Trạng_thái_cơ_thể_hiện_tại || 'Chưa rõ');
        $('#sister-thought').html(s.Suy_nghĩ_trong_lòng && s.Suy_nghĩ_trong_lòng !== 'Không' ? `<span class="content">${s.Suy_nghĩ_trong_lòng}</span>` : '<span class="thought-empty">Không</span>');

        const orders = _.get(vars, 'stat_data.Đơn_hàng_chờ_nhận', {});
        const list = $('#order-list');
        list.empty();

        const keys = Object.keys(orders).filter(k => {
          const status = orders[k].Trạng_thái_đơn_hàng;
          return status && !['Đã hoàn thành', 'Đã từ chối', 'Đã hủy'].includes(status);
        });

        const pending = keys.filter(k => {
          const status = orders[k].Trạng_thái_đơn_hàng;
          return status === 'Chờ xác nhận';
        }).length;

        if (pending > 0) {
          $('#order-badge').text(pending).removeClass('hidden');
        } else {
          $('#order-badge').addClass('hidden');
        }

        if (keys.length === 0) {
          list.html('<div class="empty-state"><i class="fas fa-inbox"></i><p>Chưa có đơn nào</p><p style="font-size:12px;margin-top:5px;opacity:0.7;">Bấm để làm mới</p></div>');
        } else {
          keys.sort((a, b) => {
            const aOrder = orders[a];
            const bOrder = orders[b];
            const aUrgent = aOrder.Loại_đơn_hàng === 'Đơn gấp';
            const bUrgent = bOrder.Loại_đơn_hàng === 'Đơn gấp';
            if (aUrgent && !bUrgent) return -1;
            if (!aUrgent && bUrgent) return 1;
            return 0;
          });

          keys.forEach(id => {
            const o = orders[id];
            const isUrgent = o.Loại_đơn_hàng === 'Đơn gấp';
            let sc, statusText;

            if (o.Trạng_thái_đơn_hàng === 'Chờ xác nhận') {
              sc = isUrgent ? 'urgent' : 'pending';
              statusText = isUrgent ? 'Đơn gấp' : 'Chờ xác nhận';
            } else {
              sc = 'accepted';
              statusText = 'Đã chấp nhận';
            }

            let tags = '';
            if (o.Yêu_cầu_đặc_biệt !== 'Không') tags += `<span class="order-tag">${o.Yêu_cầu_đặc_biệt}</span>`;
            if (o.Loại_khách_hàng && o.Loại_khách_hàng.includes('Phú bà')) tags += '<span class="order-tag">Vắt kiệt</span>';

            const urgentBadge = isUrgent ? '<div class="urgent-badge">⚡Đơn gấp </div>' : '';

            list.append(`
              <div class="order-card ${sc}" data-id="${id}">
                <div class="order-header">
                  <div class="order-name ${isUrgent ? 'urgent' : ''}">${o.Tên_khách_hàng || 'Chưa rõ'}</div>
                  <div class="order-status ${sc}">${statusText}</div>
                </div>
                <div class="order-detail">${o.Thân_phận_khách_hàng || 'Chưa rõ'} · ${o.Tuổi_khách_hàng || '?'} tuổi</div>
                <div class="order-detail"><i class="fas fa-map-marker-alt"></i> ${o.Địa_điểm_hẹn || 'Chưa rõ'}</div>
                ${tags ? `<div class="order-tags">${tags}</div>` : ''}
                <div class="order-price ${isUrgent ? 'urgent' : ''}"><i class="fas fa-yen-sign"></i> ¥${(o.Báo_giá || 0).toLocaleString()}${isUrgent ? ' (+50%)' : ''}</div>
                ${urgentBadge}
              </div>
            `);
          });
        }

        const c = _.get(vars, 'stat_data.Khách_hàng_hiện_tại', {}) || {};
        const cc = $('#current-customer');

        if (!c.Họ_tên || c.Họ_tên === 'Chờ khởi tạo') {
          cc.html('<div class="empty-state"><i class="fas fa-user-slash"></i><p>Hiện không có khách</p></div>');
        } else {
          const fv = c.Độ_hảo_cảm || 50;
          const fc = fv <= 40 ? 'low' : fv >= 70 ? 'high' : 'medium';

          cc.html(`
            <div class="customer-card">
              <div class="customer-name">${c.Họ_tên}</div>
              <div class="customer-info">
                <div><span style="color:var(--text-muted);">Họ tên:</span> ${c.Họ_tên || 'Chưa rõ'}</div>
                <div><span style="color:var(--text-muted);">Phân loại:</span> ${c.Phân_loại || 'Chưa rõ'}</div>
                <div><span style="color:var(--text-muted);">Tuổi:</span> ${c.Tuổi || 'Chưa rõ'} tuổi</div>
                <div><span style="color:var(--text-muted);">Vóc dáng:</span> ${c.Vóc_dáng || 'Chưa rõ'}</div>
                <div><span style="color:var(--text-muted);">Trinh tiết:</span> ${c.Còn_trinh_hay_không === 'Chờ khởi tạo' ? 'Chưa rõ' : c.Còn_trinh_hay_không ? 'Có' : 'Không'}</div>
                <div><span style="color:var(--text-muted);">Tính cách:</span> ${c.Tính_cách || 'Chưa rõ'}</div>
              </div>
              <div class="favor-display">
                <span class="favor-label">Hảo cảm</span>
                <div class="favor-bar">
                  <div class="favor-fill ${fc}" style="width:${fv}%"></div>
                </div>
                <span class="favor-value" style="color:var(--accent-${fc === 'low' ? 'red' : fc === 'high' ? 'green' : 'orange'});">${fv}</span>
              </div>
            </div>
            <div class="panel">
              <div class="panel-header"><i class="fas fa-brain"></i>Suy nghĩ trong lòng</div>
              <div class="panel-body">
                <div class="thought-bubble">${c.Suy_nghĩ_trong_lòng && c.Suy_nghĩ_trong_lòng !== 'Chờ khởi tạo' ? `<span class="content">${c.Suy_nghĩ_trong_lòng}</span>` : '<span class="thought-empty">Không</span>'}</div>
              </div>
            </div>
            <div class="panel">
              <div class="panel-header"><i class="fas fa-comment-dots"></i>Đánh giá của khách hàng</div>
              <div class="panel-body">
                <div class="thought-bubble">${c.Đánh_giá_về_user && c.Đánh_giá_về_user !== 'Chờ khởi tạo' ? `<span class="content">${c.Đánh_giá_về_user}</span>` : '<span class="thought-empty">Chưa có đánh giá</span>'}</div>
              </div>
            </div>
            <div class="panel">
              <div class="panel-header"><i class="fas fa-yen-sign"></i>Chi phí lần này</div>
              <div class="panel-body">
                <div style="font-size:17px;font-weight:600;color:var(--accent-green);text-shadow:0 0 6px hsla(140,60%,45%,0.3);">¥${(c.Chi_phí_lần_này||0).toLocaleString()}</div>
              </div>
            </div>
          `);
        }

        const reg = _.get(vars, 'stat_data.Danh_sách_khách_hàng', {}) || {};
        const rl = $('#registry-list');
        rl.empty();

        const rk = Object.keys(reg);
        if (rk.length === 0) {
          rl.html('<div class="empty-state"><i class="fas fa-address-book"></i><p>Chưa có lịch sử khách</p></div>');
        } else {
          rk.forEach(n => {
            const cl = reg[n] || {};
            const fv = cl.Độ_hảo_cảm || 50;
            const fc = fv <= 40 ? 'low' : fv >= 70 ? 'high' : 'medium';

            rl.append(`
              <div class="customer-card">
                <div class="customer-name">${n}</div>
                <div class="customer-info">
                  <div><span style="color:var(--text-muted);">Quan hệ:</span> ${cl.Loại_quan_hệ || 'Chưa rõ'}</div>
                  <div><span style="color:var(--text-muted);">Phân loại:</span> ${cl.Phân_loại || 'Chưa rõ'}</div>
                  <div><span style="color:var(--text-muted);">Tuổi:</span> ${cl.Tuổi || 'Chưa rõ'} tuổi</div>
                  <div><span style="color:var(--text-muted);">Tổng chi:</span> <span style="color:var(--accent-green);">¥${(cl.Tổng_tiêu_dùng_tích_lũy||0).toLocaleString()}</span></div>
                  <div><span style="color:var(--text-muted);">Hảo cảm:</span> <span style="color:var(--accent-${fc==='low'?'red':fc==='high'?'green':'orange'});">${fv}</span></div>
                </div>
                ${cl.Đánh_giá_về_user && cl.Đánh_giá_về_user !== 'Chờ khởi tạo' ? `<div style="margin-top:8px;padding-top:8px;border-top:1px solid var(--border-subtle);font-size:12px;color:var(--text-muted);"><i class="fas fa-quote-left" style="opacity:0.5;margin-right:4px;"></i>${cl.Đánh_giá_về_user}</div>` : ''}
              </div>
            `);
          });
        }
      }

      render();
      eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, render);

      $('.tab-btn').on('click', function() {
        const tab = $(this).data('tab');
        $('.tab-btn').removeClass('active');
        $(this).addClass('active');
        $('.tab-content').removeClass('active');
        $(`#tab-${tab}`).addClass('active');
      });

      $('#refresh-btn').on('click', async function() {
        const $btn = $(this);
        if ($btn.hasClass('spinning')) return;

        $btn.addClass('spinning');
        try {
          const result = await refreshOrders();
          const msg = result.urgent > 0 
            ? `Đã tạo ${result.total} đơn hàng (gồm ${result.urgent} đơn gấp⚡)` 
            : `Đã tạo ${result.total} đơn hàng`;
          showToast(msg, 'success');
          render();
        } catch (e) {
          showToast('Làm mới thất bại', 'error');
        } finally {
          setTimeout(() => $btn.removeClass('spinning'), 1000);
        }
      });

      $(document).on('click', '.order-card', function() {
        const id = $(this).data('id');
        const vars = getAllVariables();
        const orders = _.get(vars, 'stat_data.Đơn_hàng_chờ_nhận', {});
        const o = orders[id];
        if (!o) return;

        const msg = genMessage(id, o);
        if (copyToTavernDialog(msg)) {
          showToast('Đã nhập vào khung chat', 'success');
        } else {
          showToast('Nhập thất bại', 'error');
        }
      });
    }

    $(errorCatched(init));
  </script>
